pure fn sort_words(text: Text) -> Text {
    words = split(text, " ")
    sorted = []
    for w in words {
        inserted = false
        new_sorted = []
        for s in sorted {
            if inserted == false {
                if w < s {
                    new_sorted = append(new_sorted, w)
                    inserted = true
                }
            }
            new_sorted = append(new_sorted, s)
        }
        if inserted == false {
            new_sorted = append(new_sorted, w)
        }
        sorted = new_sorted
    }
    return join(sorted, " ")
}
