pure fn char_freq(s: Text) -> Text {
    chars = split(s, "")
    keys = []
    counts = []
    for c in chars {
        if c in keys {
            new_counts = []
            i = 0
            for k in keys {
                if k == c {
                    new_counts = append(new_counts, get(counts, i) + 1)
                } else {
                    new_counts = append(new_counts, get(counts, i))
                }
                i = i + 1
            }
            counts = new_counts
        } else {
            keys = append(keys, c)
            counts = append(counts, 1)
        }
    }
    parts = []
    i = 0
    for k in keys {
        parts = append(parts, join([k, ":", to_text(get(counts, i))], ""))
        i = i + 1
    }
    return join(parts, ", ")
}
entry main(x: Text) { return char_freq("mississippi") }

pure fn fib_n(n: Number) -> Number {
    result = []
    a = 0
    b = 1
    for i in range(0, n) {
        result = append(result, a)
        next_val = a + b
        a = b
        b = next_val
    }
    return result
}
