}
pure fn days_between_same_year(m1: Number, d1: Number, m2: Number, d2: Number) -> Number {
    days_per_month = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    first = d1
    for i in range(0, m1 - 1) { first = first + get(days_per_month, i) }
    second = d2
    for i in range(0, m2 - 1) { second = second + get(days_per_month, i) }
    return second - first
}
entry main(x: Text) {
